            DocumentBuilder builder = factory.newDocumentBuilder();
            xmlStream = getClass().getResourceAsStream(XML_FILE_PATH);

            if (xmlStream == null) {
                throw new RuntimeException("XML file not found: " + XML_FILE_PATH);
            }

            Document document = builder.parse(xmlStream);
            document.getDocumentElement().normalize();

            // Create XPath instance and compile expression
            XPathFactory xPathFactory = XPathFactory.newInstance();
            XPath xpath = xPathFactory.newXPath();

            // Escape single quotes in username to prevent XPath injection
            String escapedUsername = escapeXPathString(username);
            String xpathExpression = String.format(XPATH_TEMPLATE, escapedUsername);

            // Execute XPath query - use XPathConstants.STRING to get text content directly
            String role = (String) xpath.evaluate(xpathExpression, document, XPathConstants.STRING);

            return role != null && !role.isEmpty() ? role : null;

        } catch (Exception e) {
            // Log the exception in a real application
            // For this implementation, we'll return null on any error
            return null;
        } finally {
            // Close the input stream
            if (xmlStream != null) {
                try {
                    xmlStream.close();
                } catch (Exception e) {
                    // Ignore close exceptions
                }
            }
        }
    }

    /**
     * Escapes special characters in a string for safe use in XPath expressions.
     * This prevents XPath injection attacks.
     *
     * @param input the string to escape
     * @return the escaped string
     */
    private String escapeXPathString(String input) {
        if (input == null) {
            return "";
        }

        // Escape single quotes by replacing them with escaped version
        // If the string contains single quotes, use double quotes in XPath
        if (input.contains("'")) {
            // If it also contains double quotes, we need to use concat()
            if (input.contains("\"")) {
                // Split by single quotes and build concat expression
                String[] parts = input.split("'", -1);
                StringBuilder concatBuilder = new StringBuilder("concat(");

                for (int i = 0; i < parts.length; i++) {
                    // Escape any double quotes in the parts
                    String escapedPart = parts[i].replace("\"", "\\\"");
                    concatBuilder.append("'").append(escapedPart).append("'");
                    if (i < parts.length - 1) {
                        concatBuilder.append(", \"'\", ");
                    }
                }
                concatBuilder.append(")");
                return concatBuilder.toString();
            } else {
                // Use double quotes around the string
                return "\"" + input + "\"";
            }
        } else {
            // Use single quotes around the string
            return "'" + input + "'";
        }
    }
